BASE_DIR="/root/openclaw-instances"

# Define agent configurations
declare -A AGENTS=(
  ["mimi"]="18701:米米 - 运营总监:cli_a939ecab96b8dbd9:M7NLsknWnH74kHWRnqeYeffcaV5taxki"
  ["tuitui"]="18702:推推 - 小红书运营:cli_a939e8111d381bce:3h760LU7bogy3uWLUlqcVePxoGeNlxtG"
  ["xiaoxiao"]="18703:小小 - 设计师:cli_a939ef8508781bca:OfDt6pmBF9P4n6rTRO3kPJHTs67ZL2Jj"
  ["anan"]="18704:安安 - 技术员:cli_a939e8f31a0a5bd2:cFj3gRo65uBI351JqqCLPgTC635IqPDs"
)

# Generate gateway tokens for each agent
declare -A GATEWAY_TOKENS=(
  ["mimi"]="token-mimi-4e62aee4fb7b8c4c"
  ["tuitui"]="token-tuitui-5f73bff5gc8c9d5d"
  ["xiaoxiao"]="token-xiaoxiao-6g84cgg6hd9d0e6e"
  ["anan"]="token-anan-7h95dhh7ie0e1f7f"
)

# A2A gateway will run on mimi instance (18701)
GATEWAY_PORT=18701
GATEWAY_TOKEN="gateway-master-4e62aee4fb7b8c4cdf4ae5fa6191bbf9"

for agent_id in "${!AGENTS[@]}"; do
  IFS=':' read -r port name app_id app_secret <<< "${AGENTS[$agent_id]}"
  token="${GATEWAY_TOKENS[$agent_id]}"
  config_dir="$BASE_DIR/$agent_id/.openclaw"
  workspace_dir="$BASE_DIR/$agent_id/workspace"

  mkdir -p "$config_dir" "$workspace_dir"

  # Build peer list for A2A (other agents)
  peers=""
  for peer_id in "${!AGENTS[@]}"; do
    if [ "$peer_id" != "$agent_id" ]; then
      IFS=':' read -r peer_port peer_name _ _ <<< "${AGENTS[$peer_id]}"
      peer_token="${GATEWAY_TOKENS[$peer_id]}"
      peers="$peers,\"$peer_id\":{\"url\":\"http://127.0.0.1:$peer_port\",\"token\":\"$peer_token\"}"
    fi
  done
  peers="${peers:1}"  # remove leading comma

  cat > "$config_dir/openclaw.json" << CONFIG
{
  "meta": {
    "lastTouchedVersion": "2026.3.13",
    "lastTouchedAt": "$(date -u +"%Y-%m-%dT%H:%M:%SZ")"
  },
  "models": {
    "mode": "merge",
    "providers": {
      "火山引擎": {
        "baseUrl": "https://api.bytehouse-volc.com/v1",
        "apiKey": "8c22373b-404a-4f89-8ac0-50992681d1f3",
        "api": "openai-completions",
        "models": [
          {
            "id": "doubao-pro-32k",
            "name": "doubao-pro-32k",
            "reasoning": false,
            "input": ["text", "image"]
          }
        ]
      }
    }
  },
  "agents": {
    "defaults": {
      "model": {
        "primary": "火山引擎/doubao-pro-32k"
      },
      "workspace": "$workspace_dir",
      "compaction": {
        "mode": "safeguard"
      }
    },
    "list": [
      {
        "id": "$agent_id",
        "default": true,
        "name": "$name",
        "workspace": "$workspace_dir"
      }
    ]
  },
  "tools": {
    "profile": "full"
  },
  "bindings": [
    {
      "agentId": "$agent_id",
      "match": {
        "channel": "feishu",
        "accountId": "$agent_id"
      }
    }
  ],
  "commands": {
    "native": "auto",
    "nativeSkills": "auto",
    "restart": true,
    "ownerDisplay": "raw"
  },
  "session": {
    "dmScope": "per-account-channel-peer"
  },
  "channels": {
    "feishu": {
      "enabled": true,
      "threadSession": true,
      "replyMode": "auto",
      "connectionMode": "websocket",
      "domain": "feishu",
      "groupPolicy": "mention",
      "dmPolicy": "pairing",
      "accounts": {
        "$agent_id": {
          "appId": "$app_id",
          "appSecret": "$app_secret",
          "botName": "$name",
          "groupPolicy": "mention",
          "dmPolicy": "pairing"
        }
      }
    }
  },
  "gateway": {
    "port": $port,
    "mode": "local",
    "bind": "lan",
    "auth": {
      "mode": "token",
      "token": "$token"
    }
  },
  "plugins": {
    "allow": ["feishu", "a2a-gateway"],
    "load": {
      "paths": ["/root/.npm-global/lib/node_modules/openclaw/extensions/feishu"]
    },
    "entries": {
      "feishu": {
        "enabled": true
      },
      "a2a-gateway": {
        "enabled": true,
        "config": {
          "agentCard": {
            "name": "$agent_id",
            "description": "$name",
            "skills": [
              {
                "id": "chat",
                "name": "Chat",
                "description": "Chat with $name"
              }
            ]
          },
          "peers": {$peers}
        }
      }
    }
  }
}
CONFIG

  echo "Generated config for $agent_id on port $port"
done

echo "All configs generated successfully!"
