  "type": "module",
  "description": "OpenClaw A2A gateway plugin implementing the A2A v0.3.0 protocol surface",
  "main": "index.ts",
  "scripts": {
    "test": "node --import tsx --test tests/*.test.ts"
  },
  "dependencies": {
    "@a2a-js/sdk": "^0.3.0",
    "@bufbuild/protobuf": "^2.11.0",
    "@grpc/grpc-js": "^1.14.3",
    "express": "^4.21.2",
    "uuid": "^9.0.1"
  },
  "openclaw": {
    "extensions": [
      "./index.ts"
    ]
  },
  "devDependencies": {
    "@types/express": "^5.0.6",
