    "@types/supertest": "^2.0.16",
    "@types/uuid": "^10.0.0",
    "openclaw": "^2026.3.2",
    "supertest": "^7.1.4",
    "tsx": "^4.19.0",
    "typescript": "^5.9.3"
  }
}

